solution: class Solution {
public:
    int minAddToMakeValid(string s) {
        int openNeeded = 0, balance = 0;
        for (char c : s) {
            if (c == '(') {
                ++balance;
            } else {
                if (balance == 0) {
                    ++openNeeded;
                } else {
                    --balance;
                }
            }
        }
        return openNeeded + balance;
    }
};
